import java.util.*;

public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        Map<Long, List<Long>> elementIndices = new HashMap<>();
        Set<Long> uniqueElements = new HashSet<>();

        for (int i = 0; i < nums.length; i++) {
            long num = nums[i];
            if (!elementIndices.containsKey(num)) {
                elementIndices.put(num, new ArrayList<>());
                uniqueElements.add(num);
            }
            elementIndices.get(num).add((long) i);
        }

        List<Long> ans = new ArrayList<>();
        for (long[] query : queries) {
            long l = query[0], r = query[1], t = query[2];
            long subLength = r - l + 1;

            if (t > subLength) {
                ans.add(-1);
                continue;
            }

            List<Map.Entry<Long, Long>> candidates = new ArrayList<>();
            for (Long x : uniqueElements) {
                List<Long> indices = elementIndices.get(x);
                int low = bisectLeft(indices, l);
                int high = bisectRight(indices, r);
                long count = high - low;
                if (count >= t) {
                    candidates.add(Map.entry(x, count));
                }
            }

            if (candidates.isEmpty()) {
                ans.add(-1);
                continue;
            }

            long maxCount = -1;
            long bestNum = -1;
            for (Map.Entry<Long, Long> entry : candidates) {
                long num = entry.getKey();
                long cnt = entry.getValue();
                if (cnt > maxCount || (cnt == maxCount && num < bestNum)) {
                    maxCount = cnt;
                    bestNum = num;
                }
            }
            ans.add(bestNum);
        }

        return ans.stream().mapToLong(Long::longValue).toArray();
    }

    private static int bisectLeft(List<Long> list, long target) {
        int left = 0;
        int right = list.size();
        while (left < right) {
            int mid = (left + right) / 2;
            if (list.get(mid) < target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    }

    private static int bisectRight(List<Long> list, long target) {
        int left = 0;
        int right = list.size();
        while (left < right) {
            int mid = (left + right) / 2;
            if (list.get(mid) <= target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    }
}
