public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        Map<Long, List<Long>> elementIndices = new HashMap<>();
        Set<Long> uniqueElements = new HashSet<>();
        for (int i = 0; i < nums.length; i++) {
            long num = nums[i];
            if (!elementIndices.containsKey(num)) {
