            for (Long x : uniqueElements) {
                List<Long> indices = elementIndices.get(x);
                int low = Collections.binarySearch(indices, l);
                if (low < 0) {
                    low = -low - 1;
                }
                int high = Collections.binarySearch(indices, r + 1);
                if (high < 0) {
                    high = -high - 1;
