import java.util.*;

public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        Map<Long, List<Long>> elementIndices = new HashMap<>();
        Set<Long> uniqueElements = new HashSet<>();
        for (int i = 0; i < nums.length; i++) {
            long num = nums[i];
            if (!elementIndices.containsKey(num)) {
                elementIndices.put(num, new ArrayList<>());
                uniqueElements.add(num);
            }
            elementIndices.get(num).add((long) i);
        }

        List<Long> ans = new ArrayList<>();
        for (long[] query : queries) {
            long l = query[0], r = query[1], t = query[2];
            long subLength = r - l + 1;
            if (t > subLength) {
                ans.add(-1);
                continue;
            }

            List<ElementInfo> candidates = new ArrayList<>();
            for (Long element : uniqueElements) {
                List<Long> indices = elementIndices.get(element);
                int low = bisectLeft(indices, l);
                int high = bisectRight(indices, r);
                long count = high - low;
                if (count >= t) {
                    candidates.add(new ElementInfo(element, count));
                }
            }

            if (candidates.isEmpty()) {
                ans.add(-1);
            } else {
                long maxCount = -1;
                long bestNum = -1;
                for (ElementInfo info : candidates) {
                    if (info.count > maxCount || (info.count == maxCount && info.element < bestNum)) {
                        maxCount = info.count;
                        bestNum = info.element;
                    }
                }
                ans.add(bestNum);
            }
        }

        return ans.stream().mapToLong(l -> l).toArray();
    }

    private static int bisectLeft(List<Long> indices, long target) {
        int left = 0, right = indices.size();
        while (left < right) {
            int mid = (left + right) / 2;
            if (indices.get(mid) < target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    }

    private static int bisectRight(List<Long> indices, long target) {
        int left = 0, right = indices.size();
        while (left < right) {
            int mid = (left + right) / 2;
            if (indices.get(mid) <= target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    }

    static class ElementInfo {
        long element;
        long count;

        ElementInfo(long e, long c) {
            element = e;
            count = c;
        }
    }
}
